_SCORE_DATES = [d for d, _ in CRYPTO_RISK_SCORE]


def _safe(v: Any, default: float = 0.0) -> float:
    try:
        f = float(v)
    except Exception:
        return default
    return f if math.isfinite(f) else default


def _pivot(prices: pd.DataFrame, field: str) -> pd.DataFrame:
    px = prices.copy()
    px['timestamp'] = pd.to_datetime(px['timestamp'], utc=True)
    return px.pivot(index='timestamp', columns='symbol', values=field).sort_index().ffill()


def _asof_date(context: Any, prices: pd.DataFrame) -> str | None:
    for name in ('as_of', 'timestamp', 'current_time', 'now', 'date'):
        v = getattr(context, name, None)
        if v is not None:
            try:
                ts = pd.Timestamp(v)
                return ts.strftime('%Y-%m-%d')
            except Exception:
                pass
    if prices is not None and len(prices):
        return pd.to_datetime(prices['timestamp']).max().strftime('%Y-%m-%d')
    return None


def _crypto_score(asof_yyyy_mm_dd: str) -> float:
    idx = bisect.bisect_right(_SCORE_DATES, asof_yyyy_mm_dd) - 1
    if idx < 0:
        return 0.0
    return float(CRYPTO_RISK_SCORE[idx][1])


def _ret(close: pd.DataFrame, sym: str, n: int) -> float:
    if sym not in close:
        return 0.0
    s = close[sym].dropna()
    if len(s) <= n:
        return 0.0
    return _safe(s.iloc[-1] / s.iloc[-1 - n] - 1.0)


def _vol(close: pd.DataFrame, sym: str, n: int) -> float:
    if sym not in close:
        return 0.25
    r = close[sym].pct_change().dropna().tail(n)
    if len(r) < max(10, n // 2):
        return 0.25
    return max(0.04, _safe(r.std() * math.sqrt(252), 0.25))


def _cap_normalize(raw: dict[str, float], symbols: list[str]) -> dict[str, float]:
    vals = {s: max(0.0, _safe(raw.get(s, 0.0))) for s in symbols}
    gross = sum(vals.values())
    if gross <= 0:
        return {s: (1.0 if s == 'SHY' else 0.0) for s in symbols}
    w = {s: vals[s] / gross for s in symbols}
    for _ in range(8):
        excess = sum(max(0.0, v - MAX_WEIGHT) for v in w.values())
        w = {s: min(v, MAX_WEIGHT) for s, v in w.items()}
        room = {s: MAX_WEIGHT - v for s, v in w.items() if v < MAX_WEIGHT - 1e-12}
        if excess <= 1e-12 or not room:
            break
        total_room = sum(room.values())
        for s, r in room.items():
            w[s] += excess * r / total_room
    total = sum(w.values())
    return {s: (v / total if total > 0 else 0.0) for s, v in w.items()}


def generate_signals(context: Any) -> dict[str, float]:
    """Return long-only ETF weights from lagged BTC/ETH risk appetite plus ETF confirmation."""
    symbols = list(getattr(context, 'symbols', UNIVERSE) or UNIVERSE)
    prices = getattr(context, 'prices', None)
    out = {s: 0.0 for s in symbols}
    if prices is None or len(prices) < 90:
        return out
    asof = _asof_date(context, prices)
    if asof is None:
        return out
    score = _crypto_score(asof)
    close = _pivot(prices, 'close').reindex(columns=[s for s in symbols if s in UNIVERSE]).ffill()
    if close.empty:
        return out
    spy_mom = 0.55 * _ret(close, 'SPY', 63) + 0.45 * _ret(close, 'QQQ', 63)
    raw: dict[str, float] = {}
    risk_on = (score > 0.20 and spy_mom > -0.05) or (score > 0.60 and spy_mom > -0.10)
    risk_off = score < -0.35 or spy_mom < -0.12
    if risk_on:
        for s in RISK_ON:
            if s in symbols and s in close:
                mom = 0.65 * _ret(close, s, 21) + 0.35 * _ret(close, s, 63)
                inv_vol = 0.16 / _vol(close, s, 21)
                raw[s] = (0.35 + max(mom, -0.03) * 3.0 + max(score, 0.0) * 0.20) * inv_vol
        for s in ['SHY','GLD']:
            if s in symbols:
                raw[s] = 0.05
    elif risk_off:
        for s in DEFENSIVE:
            if s in symbols and s in close:
                mom = 0.50 * _ret(close, s, 21) + 0.50 * _ret(close, s, 63)
                raw[s] = 0.35 + max(mom, 0.0) * 4.0
        if 'SHY' in symbols:
            raw['SHY'] = raw.get('SHY', 0.0) + 0.45
    else:
        for s in ['SPY','QQQ','IEF','GLD','XLP','XLV','SHY']:
            if s in symbols and s in close:
                mom = 0.50 * _ret(close, s, 21) + 0.50 * _ret(close, s, 63)
                raw[s] = 0.30 + max(mom, 0.0) * 2.0
    norm = _cap_normalize(raw, symbols)
    return {s: float(norm.get(s, 0.0)) for s in symbols}
